445	// isNodeSelectorConfiguredForArchitecture returns true if the pod has already a nodeSelector for the architecture label
446	// or if all the nodeSelectorTerms in the nodeAffinity field have a matchExpression for the architecture label.
447	func (pod *Pod) isNodeSelectorConfiguredForArchitecture() bool {
448		// if the pod has the nodeSelector field set for the kubernetes.io/arch label, we ignore it.
449		// in fact, the nodeSelector field is ANDed with the nodeAffinity field, and we want to give the user the main control, if they
450		// manually set a predicate for the kubernetes.io/arch label.
451		// The same behavior is implemented below within each
452		// nodeSelectorTerm's MatchExpressions field.
453		for key := range pod.Spec.NodeSelector {
454			if key == utils.ArchLabel {
455				pod.publishIgnorePod()
456				return true
457			}
458		}
459		// Check if Affinity, NodeAffinity, or RequiredDuringSchedulingIgnoredDuringExecution is nil
460		// If any of these are nil, assume there are no specific node selector terms to check, so return true.
461		if pod.Spec.Affinity == nil || pod.Spec.Affinity.NodeAffinity == nil || pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution == nil {
462			return false
463		}
464	
465		// Iterate over NodeSelectorTerms (terms are ORed)
466		for _, nodeSelectorTerm := range pod.Spec.Affinity.NodeAffinity.RequiredDuringSchedulingIgnoredDuringExecution.NodeSelectorTerms {
467			// Assume the architecture label is not present
468			hasArchLabel := false
469	
470			// Check all match expressions within the current NodeSelectorTerm (expressions are ANDed)
471			for _, matchExpression := range nodeSelectorTerm.MatchExpressions {
472				// If we find the architecture label, mark it as found
473				if matchExpression.Key == utils.ArchLabel {
474					hasArchLabel = true
475					break
476				}
477			}
478	
479			// If one of the NodeSelectorTerms does not have the architecture label, return false
480			if !hasArchLabel {
481				return false
482			}
483	
484		}
485	
486		// If all NodeSelectorTerms contain the architecture label, return true
487		return true
488	}
