45	func IsResourceAvailable(ctx context.Context, client *dynamic.DynamicClient, resource schema.GroupVersionResource) bool {
46		rwMutex.RLock()
47		if v, ok := availableResourcesMap[resource]; ok {
48			rwMutex.RUnlock()
49			return v
