51		rwMutex.RUnlock()
52		_, err := client.Resource(resource).Namespace(Namespace()).List(ctx, metav1.ListOptions{})
53		rwMutex.Lock()
54		defer rwMutex.Unlock()
55		availableResourcesMap[resource] = err == nil
